const aws = @import("aws");

const LinkedWhatsAppBusinessAccountIdMetaData = @import("linked_whats_app_business_account_id_meta_data.zig").LinkedWhatsAppBusinessAccountIdMetaData;

/// Contains the results of WhatsAppSignupCallback.
pub const WhatsAppSignupCallbackResult = struct {
    /// An Amazon Web Services access token generated by `WhatsAppSignupCallback`
    /// and used by `WhatsAppSetupFinalization`.
    associate_in_progress_token: ?[]const u8 = null,

    /// A LinkedWhatsAppBusinessAccountIdMetaData object map containing the details
    /// of any WhatsAppBusiness accounts that have incomplete setup.
    linked_accounts_with_incomplete_setup: ?[]const aws.map.MapEntry(LinkedWhatsAppBusinessAccountIdMetaData) = null,

    pub const json_field_names = .{
        .associate_in_progress_token = "associateInProgressToken",
        .linked_accounts_with_incomplete_setup = "linkedAccountsWithIncompleteSetup",
    };
};
